1	/**
2	 * Insights engine — bottleneck detection, cost estimation, parallelism gaps, stuck signals.
3	 */
4	
5	import type { Agent, State, ToolCall } from "./models.js";
6	import { createHash } from "node:crypto";
7	import { PRICING, detectModel, priceUsd, type ModelKey } from "./shared/pricing.js";
8	
9	// ── Pricing constants (per million tokens) ────────────────────────────────
10	// Re-exported for backward compat with existing tests. Canonical source:
11	// `src/shared/pricing.ts`.
12	export const SONNET_INPUT = PRICING.sonnet.input;
13	export const SONNET_OUTPUT = PRICING.sonnet.output;
14	export const SONNET_CACHE_READ = PRICING.sonnet.cacheRead;
15	export const SONNET_CACHE_WRITE = PRICING.sonnet.cacheWrite;
16	export const OPUS_INPUT = PRICING.opus.input;
17	export const OPUS_OUTPUT = PRICING.opus.output;
18	export const OPUS_CACHE_READ = PRICING.opus.cacheRead;
19	export const OPUS_CACHE_WRITE = PRICING.opus.cacheWrite;
20	export const HAIKU_INPUT = PRICING.haiku.input;
21	export const HAIKU_OUTPUT = PRICING.haiku.output;
22	export const HAIKU_CACHE_READ = PRICING.haiku.cacheRead;
23	export const HAIKU_CACHE_WRITE = PRICING.haiku.cacheWrite;
24	
25	// ── Bottleneck ────────────────────────────────────────────────────────────
26	
27	export interface BottleneckResult {
28	  longestAgent: Agent | null;
29	  highestErrorAgent: Agent | null;
30	  longestDurationMs: number;
31	  highestErrorCount: number;
32	}
33	
34	export function bottleneck(state: State): BottleneckResult {
35	  let longestAgent: Agent | null = null;
36	  let longestDurationMs = 0;
37	  let highestErrorAgent: Agent | null = null;
38	  let highestErrorCount = 0;
39	
40	  for (const agent of state.agents.values()) {
41	    const duration = agent.last_seen_ms - agent.first_seen_ms;
42	    if (duration > longestDurationMs) {
43	      longestDurationMs = duration;
44	      longestAgent = agent;
45	    }
46	    if (agent.error_count > highestErrorCount) {
47	      highestErrorCount = agent.error_count;
48	      highestErrorAgent = agent;
49	    }
50	  }
51	
52	  return { longestAgent, highestErrorAgent, longestDurationMs, highestErrorCount };
53	}
54	
55	// ── Cost estimation ───────────────────────────────────────────────────────
56	
57	export interface AgentCost {
58	  agentId: string;
59	  agentName: string;
60	  inputTokens: number;
61	  outputTokens: number;
62	  cacheReadTokens: number;
63	  cacheCreationTokens: number;
64	  usd: number;
65	  model: ModelKey;
66	}
67	
68	export interface CostEstimateResult {
69	  perAgent: AgentCost[];
70	  totalUsd: number;
71	}
72	
73	export interface AgentCostWithSource extends AgentCost {
74	  source: "measured" | "estimated_chars" | "tool_count_fallback";
75	}
76	
77	export interface CostEstimateResultWithSource {
78	  perAgent: AgentCostWithSource[];
79	  totalUsd: number;
80	  source: "measured" | "estimated_chars" | "tool_count_fallback";
81	}
82	
83	/**
84	 * Estimate USD cost per agent.
85	 *
86	 * When tokensMap is provided (from transcript), uses those as measured values.
87	 * Otherwise reads token counts from events if present (fields: input_tokens, output_tokens, model).
88	 */
89	export function costEstimate(
90	  state: State,
91	  tokensMap?: Record<string, { input_tokens: number; output_tokens: number; cache_read: number; cache_creation: number }>
92	): CostEstimateResultWithSource {
93	  const perAgent: AgentCostWithSource[] = [];
94	  let totalUsd = 0;
95	  const hasMeasured = tokensMap != null;
96	
97	  for (const agent of state.agents.values()) {
98	    let inputTokens = 0;
99	    let outputTokens = 0;
100	    let cacheReadTokens = 0;
101	    let cacheCreationTokens = 0;
102	    let model: ModelKey = "sonnet";
103	    let source: "measured" | "estimated_chars" | "tool_count_fallback" = "tool_count_fallback";
104	
105	    if (hasMeasured && tokensMap[agent.id] != null) {
106	      // Use transcript-measured tokens
107	      const t = tokensMap[agent.id]!;
108	      inputTokens = t.input_tokens;
109	      outputTokens = t.output_tokens;
110	      cacheReadTokens = t.cache_read;
111	      cacheCreationTokens = t.cache_creation;
112	      if (
113	        inputTokens > 0 ||
114	        outputTokens > 0 ||
115	        cacheReadTokens > 0 ||
116	        cacheCreationTokens > 0
117	      ) {
118	        source = "measured";
119	      }
120	    }
121	
122	    if (source === "tool_count_fallback") {
123	      // Aggregate token data from events belonging to this agent
124	      for (const event of state.events) {
125	        if (event.agent_id !== agent.id) continue;
126	        const it = event["input_tokens"];
127	        const ot = event["output_tokens"];
128	        const cr = event["cache_read"];
129	        const cw = event["cache_creation"];
130	        const m = event["model"];
131	        if (typeof it === "number") inputTokens += it;
132	        if (typeof ot === "number") outputTokens += ot;
133	        if (typeof cr === "number") cacheReadTokens += cr;
134	        if (typeof cw === "number") cacheCreationTokens += cw;
135	        if (typeof m === "string") {
136	          const detected = detectModel(m);
137	          // Promote sonnet → opus/haiku if observed; never demote
138	          if (detected !== "sonnet") model = detected;
139	        }
140	      }
141	    }
142	
143	    // Char-based fallback: sum chars from tool_calls when no token data found
144	    if (
145	      source === "tool_count_fallback" &&
146	      inputTokens === 0 &&
147	      outputTokens === 0 &&
148	      cacheReadTokens === 0 &&
149	      cacheCreationTokens === 0
150	    ) {
151	      const calls: ToolCall[] = state.tool_calls.get(agent.id) ?? [];
152	      let inputChars = 0;
153	      let outputChars = 0;
154	      for (const tc of calls) {
155	        inputChars += JSON.stringify(tc.input).length;
156	        outputChars += tc.response?.length ?? 0;
157	      }
158	      if (inputChars > 0 || outputChars > 0) {
159	        // tokens ≈ chars / 4
160	        inputTokens = Math.round(inputChars / 4);
161	        outputTokens = Math.round(outputChars / 4);
162	        source = "estimated_chars";
163	      }
164	    }
165	
166	    const usd = priceUsd(
167	      inputTokens,
168	      outputTokens,
169	      cacheReadTokens,
170	      cacheCreationTokens,
171	      model
172	    );
173	
174	    totalUsd += usd;
175	    perAgent.push({
176	      agentId: agent.id,
177	      agentName: agent.name,
178	      inputTokens,
179	      outputTokens,
180	      cacheReadTokens,
181	      cacheCreationTokens,
182	      usd: Math.round(usd * 1_000_000) / 1_000_000,
183	      model,
184	      source,
185	    });
186	  }
187	
188	  const anyMeasured = perAgent.some((a) => a.source === "measured");
189	  const anyCharEstimated = perAgent.some((a) => a.source === "estimated_chars");
190	
191	  return {
192	    perAgent,
193	    totalUsd: Math.round(totalUsd * 1_000_000) / 1_000_000,
194	    source: anyMeasured ? "measured" : anyCharEstimated ? "estimated_chars" : "tool_count_fallback",
195	  };
196	}
197	
198	// ── Parallelism gaps ──────────────────────────────────────────────────────
199	
200	export interface ParallelismGap {
201	  agents: [string, string]; // agent IDs that ran sequentially but had no dependency
202	  aEndMs: number;
203	  bStartMs: number;
204	  overlapOpportunityMs: number;
205	}
206	
207	/**
208	 * Find agents that ran sequentially but share no data dependency
209	 * (no parent-child edge between them and their time ranges don't overlap).
210	 *
211	 * Heuristic: two sibling agents (same parent) where one ended before the
212	 * other started — they could potentially have been parallelised.
213	 */
214	export function parallelismGaps(state: State): ParallelismGap[] {
215	  const gaps: ParallelismGap[] = [];
216	
217	  // Group agents by parent
218	  const byParent = new Map<string, Agent[]>();
219	  for (const agent of state.agents.values()) {
220	    if (!agent.parent_id) continue;
221	    const siblings = byParent.get(agent.parent_id) ?? [];
222	    siblings.push(agent);
223	    byParent.set(agent.parent_id, siblings);
224	  }
225	
226	  // Build edge set for dependency check
227	  const edgePairs = new Set<string>(
228	    state.edges.map((e) => `${e.from_id}|${e.to_id}`)
229	  );
230	
231	  for (const siblings of byParent.values()) {
232	    if (siblings.length < 2) continue;
233	
234	    // Sort by start time
235	    const sorted = [...siblings].sort((a, b) => a.first_seen_ms - b.first_seen_ms);
236	
237	    for (let i = 0; i < sorted.length - 1; i++) {
238	      for (let j = i + 1; j < sorted.length; j++) {
239	        const a = sorted[i]!;
240	        const b = sorted[j]!;
241	
242	        // Skip if there's a direct dependency edge between them
243	        const hasDep =
244	          edgePairs.has(`${a.id}|${b.id}`) || edgePairs.has(`${b.id}|${a.id}`);
245	        if (hasDep) continue;
246	
247	        // Check sequential: a ended before b started
248	        if (a.last_seen_ms > 0 && b.first_seen_ms > a.last_seen_ms) {
249	          const gap = b.first_seen_ms - a.last_seen_ms;
250	          gaps.push({
251	            agents: [a.id, b.id],
252	            aEndMs: a.last_seen_ms,
253	            bStartMs: b.first_seen_ms,
254	            overlapOpportunityMs: gap,
255	          });
256	        }
257	      }
258	    }
259	  }
260	
261	  // Sort by largest opportunity first
262	  return gaps.sort((a, b) => b.overlapOpportunityMs - a.overlapOpportunityMs);
263	}
264	
265	// ── Stuck signals ─────────────────────────────────────────────────────────
266	
267	export interface StuckSignal {
268	  agentId: string;
269	  agentName: string;
270	  reason: "repeated_tool" | "consecutive_failures";
271	  detail: string;
272	  tool_name?: string;
273	  count: number;
274	}
275	
276	const REPEAT_WINDOW_MS = 60_000; // 1 minute
277	const REPEAT_THRESHOLD = 3;
278	const CONSECUTIVE_FAILURE_THRESHOLD = 3;
279	
280	function hashInput(input: Record<string, unknown>): string {
281	  return createHash("sha1").update(JSON.stringify(input)).digest("hex").slice(0, 8);
282	}
283	
284	/**
285	 * Detect agents that are stuck:
286	 *   1. Repeated tool calls: same tool_name + same input hash, N times within window
287	 *   2. Consecutive failures: N consecutive PostToolUseFailure events
288	 */
289	export function stuckSignals(state: State): StuckSignal[] {
290	  const signals: StuckSignal[] = [];
291	
292	  for (const agent of state.agents.values()) {
293	    // Skip already-done agents
294	    if (agent.status === "done") continue;
295	
296	    const calls: ToolCall[] = state.tool_calls.get(agent.id) ?? [];
297	
298	    // --- Repeated tool calls ---
299	    // Group by (tool_name, input_hash) within window
300	    const buckets = new Map<string, { count: number; firstMs: number; lastMs: number }>();
301	    for (const tc of calls) {
302	      const key = `${tc.tool_name}|${hashInput(tc.input)}`;
303	      const bucket = buckets.get(key);
304	      if (!bucket) {
305	        buckets.set(key, { count: 1, firstMs: tc.started_ms, lastMs: tc.started_ms });
306	      } else {
307	        bucket.count++;
308	        bucket.lastMs = tc.started_ms;
309	      }
310	    }
311	    for (const [key, bucket] of buckets) {
312	      if (
313	        bucket.count >= REPEAT_THRESHOLD &&
314	        bucket.lastMs - bucket.firstMs <= REPEAT_WINDOW_MS
315	      ) {
316	        const [toolName] = key.split("|");
317	        signals.push({
318	          agentId: agent.id,
319	          agentName: agent.name,
320	          reason: "repeated_tool",
321	          detail: `Tool "${toolName}" called ${bucket.count} times with same input within ${REPEAT_WINDOW_MS / 1000}s`,
322	          tool_name: toolName,
323	          count: bucket.count,
324	        });
325	      }
326	    }
327	
328	    // --- Consecutive failures ---
329	    // Count trailing consecutive error tool calls
330	    let consecutiveErrors = 0;
331	    for (let i = calls.length - 1; i >= 0; i--) {
332	      const tc = calls[i]!;
333	      if (tc.status === "error") {
334	        consecutiveErrors++;
335	      } else {
336	        break;
337	      }
338	    }
339	    if (consecutiveErrors >= CONSECUTIVE_FAILURE_THRESHOLD) {
340	      signals.push({
341	        agentId: agent.id,
342	        agentName: agent.name,
343	        reason: "consecutive_failures",
344	        detail: `${consecutiveErrors} consecutive tool failures`,
345	        count: consecutiveErrors,
346	      });
347	    }
348	  }
349	
350	  return signals;
351	}
352	
353	// ── Error recovery ────────────────────────────────────────────────────────
354	
355	export type RecoveryStatus = "retried_succeeded" | "retried_failed" | "no_retry";
356	
357	export interface ErrorRecoveryEntry {
358	  agentId: string;
359	  agentName: string;
360	  tool_name: string;
361	  failed_tool_id: string;
362	  recovery: RecoveryStatus;
363	  retry_tool_id: string | null;
364	}
365	
366	const RETRY_WINDOW_MS = 60_000;
367	
368	/**
369	 * Scan tool calls for failed ones, then check if the same agent retried with
370	 * the same tool_name within 60s. Classify recovery.
371	 */
372	export function errorRecovery(state: State): ErrorRecoveryEntry[] {
373	  const entries: ErrorRecoveryEntry[] = [];
374	
375	  for (const agent of state.agents.values()) {
376	    const calls: ToolCall[] = state.tool_calls.get(agent.id) ?? [];
377	
378	    for (let i = 0; i < calls.length; i++) {
379	      const tc = calls[i]!;
380	      if (tc.status !== "error") continue;
381	
382	      // Look for a retry: same tool_name within RETRY_WINDOW_MS, after the failure
383	      let recovery: RecoveryStatus = "no_retry";
384	      let retry_tool_id: string | null = null;
385	
386	      for (let j = i + 1; j < calls.length; j++) {
387	        const candidate = calls[j]!;
388	        if (candidate.started_ms - tc.started_ms > RETRY_WINDOW_MS) break;
389	        if (candidate.tool_name !== tc.tool_name) continue;
390	        // Found a retry
391	        retry_tool_id = candidate.id;
392	        recovery = candidate.status === "done" ? "retried_succeeded" : "retried_failed";
393	        break;
394	      }
395	
396	      entries.push({
397	        agentId: agent.id,
398	        agentName: agent.name,
399	        tool_name: tc.tool_name,
400	        failed_tool_id: tc.id,
401	        recovery,
402	        retry_tool_id,
403	      });
404	    }
405	  }
406	
407	  return entries;
408	}
409	
410	// ── Agent performance table ───────────────────────────────────────────────
411	
412	export interface AgentPerfRow {
413	  id: string;
414	  name: string;
415	  type: string | null;
416	  duration_ms: number;
417	  tool_count: number;
418	  errors: number;
419	  cost_usd: number;
420	}
421	
422	/**
423	 * Build a per-agent performance table using computed cost from costEstimate.
424	 */
425	export function agentPerformanceTable(
426	  state: State,
427	  cost: CostEstimateResultWithSource
428	): AgentPerfRow[] {
429	  const costById = new Map(cost.perAgent.map((a) => [a.agentId, a.usd]));
430	
431	  return Array.from(state.agents.values()).map((agent) => ({
432	    id: agent.id,
433	    name: agent.name,
434	    type: agent.subagent_type,
435	    duration_ms: agent.last_seen_ms - agent.first_seen_ms,
436	    tool_count: agent.tool_count,
437	    errors: agent.error_count,
438	    cost_usd: costById.get(agent.id) ?? 0,
439	  }));
440	}
441	
442	// ── Agent type profiles ───────────────────────────────────────────────────
443	
444	export interface AgentTypeProfile {
445	  type: string;
446	  sample_count: number;
447	  avg_duration_ms: number;
448	  avg_tool_count: number;
449	  summary: string;
450	}
451	
452	/**
453	 * Group agents by subagent_type and produce plain-English profiles.
454	 */
455	export function agentTypeProfiles(state: State): AgentTypeProfile[] {
456	  const groups = new Map<string, { durations: number[]; toolCounts: number[] }>();
457	
458	  for (const agent of state.agents.values()) {
459	    const type = agent.subagent_type ?? "root";
460	    const g = groups.get(type) ?? { durations: [], toolCounts: [] };
461	    g.durations.push(agent.last_seen_ms - agent.first_seen_ms);
462	    g.toolCounts.push(agent.tool_count);
463	    groups.set(type, g);
464	  }
465	
466	  const profiles: AgentTypeProfile[] = [];
467	
468	  for (const [type, g] of groups) {
469	    const n = g.durations.length;
470	    const avg_duration_ms = Math.round(g.durations.reduce((a, b) => a + b, 0) / n);
471	    const avg_tool_count = Math.round(g.toolCounts.reduce((a, b) => a + b, 0) / n);
472	
473	    // Build plain-English ranges
474	    const minTools = Math.min(...g.toolCounts);
475	    const maxTools = Math.max(...g.toolCounts);
476	    const minDurS = (Math.min(...g.durations) / 1000).toFixed(1);
477	    const maxDurS = (Math.max(...g.durations) / 1000).toFixed(1);
478	
479	    const toolRange = minTools === maxTools ? `${minTools}` : `${minTools}-${maxTools}`;
480	    const durRange =
481	      minDurS === maxDurS ? `${minDurS}s` : `${minDurS}s-${maxDurS}s`;
482	
483	    const summary =
484	      `Usually makes ${toolRange} tool call${maxTools !== 1 ? "s" : ""}, ` +
485	      `takes ${durRange} ` +
486	      `(${n} sample${n !== 1 ? "s" : ""})`;
487	
488	    profiles.push({ type, sample_count: n, avg_duration_ms, avg_tool_count, summary });
489	  }
490	
491	  return profiles.sort((a, b) => b.sample_count - a.sample_count);
492	}
493	
494	// ── Agent type trends (from baselines) ────────────────────────────────────
495	
496	export interface BaselineRow {
497	  agent_type: string;
498	  mean_duration: number;
499	  mean_tool_count: number;
500	  mean_cost: number;
501	  sample_count: number;
502	  stddev_duration: number;
503	  stddev_tool_count: number;
504	  updated_at: number;
505	  tool_sequence_common?: string;
506	}
507	
508	export interface AgentTypeTrend {
509	  type: string;
510	  sample_count: number;
511	  summary: string;
512	}
513	
514	/**
515	 * Produce per-type plain-English summary from stored baselines.
516	 * Uses mean ± stddev to compute human-readable ranges.
517	 */
518	export function agentTypeTrends(baselines: BaselineRow[]): AgentTypeTrend[] {
519	  return baselines.map((b) => {
520	    const toolLow = Math.max(0, Math.round(b.mean_tool_count - b.stddev_tool_count));
521	    const toolHigh = Math.round(b.mean_tool_count + b.stddev_tool_count);
522	    const durLowS = Math.max(0, (b.mean_duration - b.stddev_duration) / 1000);
523	    const durHighS = (b.mean_duration + b.stddev_duration) / 1000;
524	
525	    const toolRange =
526	      toolLow === toolHigh
527	        ? `${toolLow}`
528	        : `${toolLow}-${toolHigh}`;
529	
530	    const durRange =
531	      Math.abs(durHighS - durLowS) < 0.05
532	        ? `${durLowS.toFixed(1)}s`
533	        : `${durLowS.toFixed(1)}-${durHighS.toFixed(1)}s`;
534	
535	    const summary =
536	      `Usually makes ${toolRange} tool call${toolHigh !== 1 ? "s" : ""}, ` +
537	      `takes ${durRange} based on ${b.sample_count} prior run${b.sample_count !== 1 ? "s" : ""}`;
538	
539	    return { type: b.agent_type, sample_count: b.sample_count, summary };
540	  });
541	}
